spec-memory memory_context

Description:
  [L1:Orchestration] Unified entry point for context retrieval with intent-aware routing. START HERE for most context-retrieval operations across indexed spec docs and constitutional rules. For session recovery, use mode: 'resume' with profile: 'resume'. Automatically detects task intent (add_feature, fix_bug, refactor, security_audit, understand, find_spec, find_decision) and routes to optimal retrieval strategy. Modes: auto (default), quick (trigger-based), deep (comprehensive), focused (intent-optimized), resume (session recovery). Token Budget: 3500. For code search, use mcp__mk_code_index__code_graph_query for structural code queries (callers, imports) and Grep for exact text or token searches.

Aliases:
  memory_context, memory-context, memoryContext

Input schema:
{
  "type": "object",
  "additionalProperties": false,
  "properties": {
    "input": {
      "type": "string",
      "minLength": 1,
      "description": "The query, prompt, or context description (required)"
    },
    "mode": {
      "type": "string",
      "enum": [
        "auto",
        "quick",
        "deep",
        "focused",
        "resume"
      ],
      "default": "auto",
      "description": "Context retrieval mode: auto (detect intent), quick (fast triggers), deep (comprehensive search), focused (intent-optimized), resume (session recovery)"
    },
    "intent": {
      "type": "string",
      "enum": [
        "add_feature",
        "fix_bug",
        "refactor",
        "security_audit",
        "understand",
        "find_spec",
        "find_decision"
      ],
      "description": "Explicit task intent. If not provided and mode=auto, intent is auto-detected from input."
    },
    "specFolder": {
      "type": "string",
      "description": "Limit context to specific spec folder"
    },
    "tenantId": {
      "type": "string",
      "description": "Tenant boundary for governed retrieval when memory_context routes to memory_search."
    },
    "userId": {
      "type": "string",
      "description": "User boundary for governed retrieval when memory_context routes to memory_search."
    },
    "agentId": {
      "type": "string",
      "description": "Agent boundary for governed retrieval when memory_context routes to memory_search."
    },
    "limit": {
      "type": "number",
      "minimum": 1,
      "maximum": 100,
      "description": "Maximum results (mode-specific defaults apply)"
    },
    "sessionId": {
      "type": "string",
      "description": "Optional server-issued session identifier for working-memory continuity. When provided, it must match an existing server-managed session or the call is rejected. Omit it to let the server generate a new session for this request."
    },
    "enableDedup": {
      "type": "boolean",
      "default": true,
      "description": "Enable session deduplication"
    },
    "includeContent": {
      "type": "boolean",
      "default": false,
      "description": "Include full file content in results"
    },
    "includeTrace": {
      "type": "boolean",
      "default": false,
      "description": "Include provenance-rich trace data (scores, source, trace) in results when underlying memory_search is called"
    },
    "tokenUsage": {
      "type": "number",
      "minimum": 0,
      "maximum": 1,
      "description": "Optional caller token usage ratio (0.0-1.0)"
    },
    "anchors": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description": "Filter content to specific anchors (e.g., [\"state\", \"next-steps\"] for resume mode)"
    },
    "profile": {
      "type": "string",
      "enum": [
        "quick",
        "research",
        "resume",
        "debug"
      ],
      "description": "Optional response profile formatter. Returns a reduced or mode-aware response shape when profile formatting is enabled."
    }
  },
  "required": [
    "input"
  ]
}

